class Solution {
    public int minLength(String s) {
        StringBuilder stack = new StringBuilder();
        for (char c : s.toCharArray()) {
            if (stack.length() > 1 && 
                ((stack.charAt(stack.length() - 2) == 'A' && c == 'B') || 
                 (stack.charAt(stack.length() - 2) == 'C' && c == 'D'))) {
                stack.delete(stack.length() - 2, stack.length());
            } else {
                stack.append(c);
            }
        }
        return stack.length();
    }
}
